CREATE TABLE IF NOT EXISTS transcripts (id VARCHAR(36) PRIMARY KEY, college_id VARCHAR(64) NOT NULL, student_id VARCHAR(36) NOT NULL, status VARCHAR(32) NOT NULL DEFAULT 'DRAFT', verification_code VARCHAR(80) NOT NULL, institution_name VARCHAR(180) NOT NULL, academic_history_json TEXT NOT NULL, summary_json TEXT NOT NULL, printable_html TEXT NOT NULL, generated_by VARCHAR(64) NOT NULL, issued_by VARCHAR(64), generated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP, issued_at TIMESTAMP WITH TIME ZONE, CONSTRAINT uq_transcript_verification UNIQUE (college_id, student_id, verification_code));
CREATE INDEX IF NOT EXISTS ix_transcripts_college_student_status ON transcripts (college_id, student_id, status);
